#define IR_SENSOR 2
#define BUZZER 8

void setup() {
  pinMode(IR_SENSOR, INPUT);
  pinMode(BUZZER, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  int motion = digitalRead(IR_SENSOR);

  if (motion == LOW) {
    digitalWrite(BUZZER, HIGH);
    Serial.println("Motion Detected!");
  }
  else {
    digitalWrite(BUZZER, LOW);
    Serial.println("No Motion");
  }

  delay(100);
}
